before_code:
module comparator_16bit(
  input [15:0] data_x, data_y, threshold,
  output reg is_valid
);

  always @(data_x or data_y) begin
    if ((data_x > threshold) || (data_y > threshold))
      is_valid = 1'b1;
    else
      is_valid = 1'b0;
  end

endmodule

after_code:
module comparator_16bit(
  input [15:0] data_x, data_y, threshold,
  output reg is_valid
);

  always @(data_x or data_y or threshold) begin
    if ((data_x > threshold) || (data_y > threshold))
      is_valid = 1'b1;
    else
      is_valid = 1'b0;
  end

endmodule
